#include <stdio.h>
#include <stdlib.h>
#define MAX_SIZE 100

int stack[MAX_SIZE];
int tempStack[MAX_SIZE];
int top = -1;
int tempTop = -1;

void push(int value) {
    stack[++top] = value;
}

int pop() {
    return stack[top--];
}

void tempPush(int value) {
    tempStack[++tempTop] = value;
}

int tempPop() {
    return tempStack[tempTop--];
}

void sortStack() {
    while (top >= 0) {
        int temp = pop();
        while (tempTop >= 0 && tempStack[tempTop] > temp) {
            push(tempPop());
        }
        tempPush(temp);
    }
    while (tempTop >= 0) {
        printf("%d\n", tempPop());
    }
}

int main() {
    int n;
    scanf("%d", &n);
    for (int i = 0; i < n; i++) {
        int value;
        scanf("%d", &value);
        push(value);
    }
    sortStack();
    return 0;
}

